1	package fan.summer.plugin;
2	
3	import fan.summer.api.SwissKitJPlugin;
4	import javafx.application.Platform;
5	import org.apache.logging.log4j.core.config.plugins.util.PluginRegistry;
6	
7	import java.io.IOException;
8	import java.net.URLClassLoader;
9	import java.nio.file.*;
10	import java.util.*;
11	import java.util.concurrent.atomic.AtomicBoolean;
12	import java.util.logging.Logger;
13	
14	/**
15	 * Scans a plugins/ directory for JAR files, loads SwissKitJPlugin implementations
16	 * via ServiceLoader, and watches for hot-reload on file changes.
17	 */
18	public class PluginLoader {
19	
20	    private static final Logger log = Logger.getLogger(PluginLoader.class.getName());
21	
22	    private final Path        pluginsDir;
23	    private PluginRegistry registry;
24	    private WatchService      watchService;
25	    private Thread            watchThread;
26	    private final AtomicBoolean running = new AtomicBoolean(false);
27	
28	    /** Maps JAR path → the ClassLoader opened for it (for unloading) */
29	    private final Map<Path, URLClassLoader> openLoaders = new LinkedHashMap<>();
30	
31	    /** Maps JAR path → plugins loaded from that JAR */
32	    private final Map<Path, List<SwissKitJPlugin>> jarPlugins = new LinkedHashMap<>();
33	
34	    public PluginLoader(Path pluginsDir) {
35	        this.pluginsDir = pluginsDir;
36	    }
37	
38	    // Called by PluginRegistry after construction
39	    void setRegistry(PluginRegistry registry) {
40	        this.registry = registry;
41	    }
42	
43	    // ── Lifecycle ────────────────────────────────────────────────
44	
45	    public void start() {
46	        if (!running.compareAndSet(false, true)) return;
47	
48	        // Initial scan
49	        scanAll();
50	
51	        // Watch for JAR add/remove
52	        try {
53	            if (Files.isDirectory(pluginsDir)) {
54	                watchService = FileSystems.getDefault().newWatchService();
55	                pluginsDir.register(watchService,
56	                    StandardWatchEventKinds.ENTRY_CREATE,
57	                    StandardWatchEventKinds.ENTRY_DELETE,
58	                    StandardWatchEventKinds.ENTRY_MODIFY
59	                );
60	                watchThread = new Thread(this::watchLoop, "plugin-watcher");
61	                watchThread.setDaemon(true);
62	                watchThread.start();
63	            }
64	        } catch (IOException e) {
65	            log.warning("Cannot start plugin watcher: " + e.getMessage());
66	        }
67	    }
68	
69	    public void stop() {
70	        running.set(false);
71	        try {
72	            if (watchService != null) watchService.close();
73	        } catch (IOException ignored) {}
74	        if (watchThread != null) watchThread.interrupt();
75	
76	        // Unload all plugins
77	        new ArrayList<>(jarPlugins.keySet()).forEach(this::unloadJar);
78	    }
79	
80	    // ── Scan ────────────────────────────────────────────────────
81	
82	    private void scanAll() {
83	        if (!Files.isDirectory(pluginsDir)) return;
84	        try (DirectoryStream<Path> stream = Files.newDirectoryStream(pluginsDir, "*.jar")) {
85	            for (Path jar : stream) {
86	                if (!jarPlugins.containsKey(jar)) loadJar(jar);
87	            }
88	        } catch (IOException e) {
89	            log.warning("Plugin scan failed: " + e.getMessage());
90	        }
91	    }
92	
93	    // ── JAR load / unload ────────────────────────────────────────
94	
95	    private void loadJar(Path jar) {
96	        try {
97	            URLClassLoader cl = new URLClassLoader(
98	                new java.net.URL[]{jar.toUri().toURL()},
99	                getClass().getClassLoader()
100	            );
101	            ServiceLoader<SwissKitJPlugin> sl = ServiceLoader.load(SwissKitJPlugin.class, cl);
102	
103	            List<SwissKitJPlugin> loaded = new ArrayList<>();
104	            for (SwissKitJPlugin plugin : sl) {
105	                loaded.add(plugin);
106	                log.info("Loaded plugin: " + plugin.getId() + " from " + jar.getFileName());
107	            }
108	
109	            if (loaded.isEmpty()) {
110	                cl.close();
111	                return;
112	            }
113	
114	            openLoaders.put(jar, cl);
115	            jarPlugins.put(jar, loaded);
116	
117	            if (registry != null) {
118	                Platform.runLater(() -> registry.addPlugins(loaded));
119	            }
120	        } catch (Exception e) {
121	            log.warning("Failed to load JAR " + jar.getFileName() + ": " + e.getMessage());
122	        }
123	    }
124	
125	    private void unloadJar(Path jar) {
126	        List<SwissKitJPlugin> plugins = jarPlugins.remove(jar);
127	        if (plugins != null && registry != null) {
128	            Platform.runLater(() -> plugins.forEach(registry::removePlugin));
129	        }
130	
131	        URLClassLoader cl = openLoaders.remove(jar);
132	        if (cl != null) {
133	            try { cl.close(); } catch (IOException ignored) {}
134	        }
135	    }
136	
137	    // ── Watch loop ───────────────────────────────────────────────
138	
139	    private void watchLoop() {
140	        while (running.get()) {
141	            try {
142	                WatchKey key = watchService.take();
143	                for (WatchEvent<?> event : key.pollEvents()) {
144	                    Path name    = (Path) event.context();
145	                    Path fullPath = pluginsDir.resolve(name);
146	
147	                    if (!name.toString().endsWith(".jar")) continue;
148	
149	                    WatchEvent.Kind<?> kind = event.kind();
150	                    if (kind == StandardWatchEventKinds.ENTRY_CREATE) {
151	                        // Brief delay so the file is fully written before reading
152	                        Thread.sleep(500);
153	                        loadJar(fullPath);
154	                    } else if (kind == StandardWatchEventKinds.ENTRY_DELETE) {
155	                        unloadJar(fullPath);
156	                    } else if (kind == StandardWatchEventKinds.ENTRY_MODIFY) {
157	                        unloadJar(fullPath);
158	                        Thread.sleep(500);
159	                        loadJar(fullPath);
160	                    }
161	                }
162	                key.reset();
163	            } catch (InterruptedException e) {
164	                Thread.currentThread().interrupt();
165	                break;
166	            } catch (ClosedWatchServiceException e) {
167	                break;
168	            }
169	        }
170	    }
171	}
