1	package fan.summer.plugin;
2	
3	import fan.summer.api.SwissKitJPlugin;
4	import javafx.collections.FXCollections;
5	import javafx.collections.ObservableList;
6	
7	import java.util.List;
8	
9	/**
10	 * Holds the live plugin list and manages plugin activation lifecycle.
11	 * Built-in tools are added directly via getPlugins().addAll();
12	 * external JAR plugins are added/removed by PluginLoader.
13	 */
14	public class PluginRegistry {
15	
16	    private final ObservableList<SwissKitJPlugin> plugins =
17	        FXCollections.observableArrayList();
18	
19	    private SwissKitJPlugin activePlugin;
20	
21	    public PluginRegistry(PluginLoader loader) {
22	        loader.setRegistry(this);
23	    }
24	
25	    // ── Plugin list ──────────────────────────────────────────────
26	
27	    public ObservableList<SwissKitJPlugin> getPlugins() {
28	        return plugins;
29	    }
30	
31	    // Called by PluginLoader (already on FX thread via Platform.runLater)
32	    void addPlugins(List<SwissKitJPlugin> toAdd) {
33	        plugins.addAll(toAdd);
34	    }
35	
36	    // Called by PluginLoader (already on FX thread via Platform.runLater)
37	    void removePlugin(SwissKitJPlugin plugin) {
38	        if (activePlugin == plugin) {
39	            plugin.onDeactivate();
40	            activePlugin = null;
41	        }
42	        plugin.onUnload();
43	        plugins.remove(plugin);
44	    }
45	
46	    // ── Lifecycle ────────────────────────────────────────────────
47	
48	    /**
49	     * Activate a plugin: deactivates the currently active one first.
50	     */
51	    public void activate(SwissKitJPlugin plugin) {
52	        if (activePlugin != null && activePlugin != plugin) {
53	            activePlugin.onDeactivate();
54	        }
55	        activePlugin = plugin;
56	        plugin.onActivate();
57	    }
58	
59	    public SwissKitJPlugin getActivePlugin() {
60	        return activePlugin;
61	    }
62	}
