23	@SwissKitPage(pluginName = "KeepMove", pluginVersion = "1.0.0", menuName = "KeepMove", menuTooltip = "KeepMove", order = 9)
24	public class KeepMove implements LocaleChangeListener {
25	    // Robot instance for controlling mouse movement
26	    private Robot robot;
27	    // Timer for scheduling periodic mouse movement
28	    private Timer timer;
29	    // Random for expert mode movement randomization
30	    private Random random = new Random();
31	    // Track last human input time for expert mode
32	    private volatile long lastHumanInputTime = System.currentTimeMillis();
33	    // Global input listeners for detecting human activity
34	    private AWTEventListener humanInputListener;
35	    // Expert mode state
36	    private boolean expertMode = true;
37	    // Expert mode: minimum interval between synthetic events
38	    private static final int EXPERT_MIN_INTERVAL_MS = 15_000;  // 15 seconds minimum
39	    // Expert mode: maximum interval between synthetic events
40	    private static final int EXPERT_MAX_INTERVAL_MS = 45_000;  // 45 seconds maximum
41	    // Expert mode: minimum movement distance
42	    private static final int EXPERT_MIN_MOVE = 10;
43	    // Expert mode: maximum movement distance
44	    private static final int EXPERT_MAX_MOVE = 50;
45	
46	    public KeepMove() {
47	        initComponents();
48	        I18nManager.addListener(this);
49	        refreshI18n();
50	        // Initialize Robot to control mouse cursor
51	        try {
52	            robot = new Robot();
53	        } catch (AWTException e) {
54	            e.printStackTrace();
55	        }
56	        // Set initial button states - Stop is disabled until movement starts
57	        stopMoveBt.setEnabled(false);
58	        setupEventHandlers();
59	        setupHumanInputDetection();
60	    }
61	
