204	        // JFormDesigner - Component initialization - DO NOT MODIFY  //GEN-BEGIN:initComponents  @formatter:off
205	        mouse = new JPanel();
206	        startMoveBt = new JButton();
207	        stopMoveBt = new JButton();
208	
209	        //======== mouse ========
210	        {
211	            mouse.setLayout(new MigLayout(
212	                "fill,hidemode 3,alignx center",
213	                // columns
214	                "[fill]" +
215	                "[fill]",
216	                // rows
217	                "[]" +
218	                "[]" +
219	                "[]"));
220	
221	            //---- startMoveBt ----
222	            startMoveBt.setText("StartMove");
223	            mouse.add(startMoveBt, "cell 0 1");
224	
225	            //---- stopMoveBt ----
226	            stopMoveBt.setText("StopMove");
227	            mouse.add(stopMoveBt, "cell 1 1");
228	        }
229	        // JFormDesigner - End of component initialization  //GEN-END:initComponents  @formatter:on
230	    }
